第二题：设将n(n&gt;1)个整数存放到一维数组R中,设计一个算法,将R中保存的序列循环左移p(O&lt;p&lt;n)个位置,即将R中的数据由(r0, r1,…,rn-1)变换为(rp,rp+1,…,rn-1,r0,r1,…,rp-1)。
首先声明，作者的做法大概率是错的，这一题的做法应该使用循环链表


算法思想

要将n个整数存放到一维数组而且能左移n个位置，就要先定义一个长度至少为2n的数组因为是将元素左移，所以将元素内容储存在数组下标较大的一端然后从第一个元素开始遍历数组R，将下标为i的元素和下标为i-p的元素交换最后输出数组，验证算法是否成功

代码实现

#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#define N 14        //n为7，所以数组最大长度N应该至少为14int main()&#123;    int n = 7;    int R[N] = &#123; 0 &#125;;        //定义一维数组R    for (int i = N - n; i &lt; N; i++)        //将n个整数存放到R中        R[i] = i;    printf(&quot;数组下标：&quot;);        //输出下标    for (int i = 0; i &lt; N; i++)        printf(&quot;%d\t&quot;, i);    printf(&quot;\n\n移动之前：&quot;);        //输出移动元素前下标对应的元素    for (int i = 0; i &lt; N; i++)        printf(&quot;%d\t&quot;, R[i]);    int temp = 0;    int p = 5;    for (int i = N - n; i &lt; N; i++)        //从第一个元素开始交换    &#123;        if (p &gt; n || p &lt; 0)        //保证0&lt;p&lt;n，超出范围跳出循环        &#123;            printf(&quot;不能这么移动！&quot;);            break;        &#125;        temp = R[i - p];        R[i - p] = R[i];        R[i] = temp;    &#125;    printf(&quot;\n\n移动之后：&quot;);        //输出移动元素后下标对应的元素    for (int i = 0; i &lt; N; i++)        printf(&quot;%d\t&quot;, R[i]);&#125;


